import type { RevealInteractionConfig, RevealTrailConfig } from "../../types";
import type { PointerSnapshot } from "../renderer/types";
import { DEFAULT_REVEAL } from "../renderer/types";
import { clamp01 } from "../utils/color";

export const BROWSERBASE_REVEAL_PRESET = DEFAULT_REVEAL;

export const DEFAULT_REVEAL_TRAIL: Required<RevealTrailConfig> = {
  dustFlicker: 0,
  dustSize: 2,
  durationMs: 900,
  idleMs: 160,
  maxPoints: 24,
  spacing: 18,
  strength: 0.72
};

const EDGE_NOISE_CELL_SIZE = 18;
const EDGE_NOISE_MAX_WIDTH_MULTIPLIER = 0.7;
const DUST_FLICKER_SEED_SCALE = 17.17;
const DUST_FLICKER_STEP_MS = 80;
const EDGE_FLICKER_SEED_SCALE = 23.37;
const EDGE_FLICKER_STEP_MS = 90;

export const REVEAL_DITHER_MATRIX = [
  [0, 8, 2, 10],
  [12, 4, 14, 6],
  [3, 11, 1, 9],
  [15, 7, 13, 5]
] as const;

export type ResolvedRevealConfig = Required<RevealInteractionConfig>;
export type ResolvedRevealTrailConfig = Required<RevealTrailConfig>;

export type RevealMaskSample = {
  x: number;
  y: number;
  pointer: PointerSnapshot;
  reveal?: RevealInteractionConfig | false;
  time?: number;
};

export type RevealFadeInput = {
  active: boolean;
  elapsedSinceInactiveMs?: number;
  fadeMs?: number;
  reducedMotion?: boolean;
};

export function resolveRevealConfig(
  reveal: RevealInteractionConfig | false | undefined
): ResolvedRevealConfig {
  return {
    ...BROWSERBASE_REVEAL_PRESET,
    ...(reveal || {})
  };
}

export function resolveRevealTrailConfig(
  trail: RevealInteractionConfig["trail"]
): ResolvedRevealTrailConfig | false {
  if (!trail) {
    return false;
  }

  if (trail === true) {
    return DEFAULT_REVEAL_TRAIL;
  }

  return {
    ...DEFAULT_REVEAL_TRAIL,
    ...trail
  };
}

export function getRevealFade({
  active,
  elapsedSinceInactiveMs = 0,
  fadeMs = BROWSERBASE_REVEAL_PRESET.fadeMs,
  reducedMotion = false
}: RevealFadeInput): number {
  if (active) {
    return 1;
  }

  if (reducedMotion || fadeMs <= 0) {
    return 0;
  }

  return clamp01(1 - Math.max(0, elapsedSinceInactiveMs) / fadeMs);
}

export function isRevealFadeActive(pointer: PointerSnapshot): boolean {
  return !pointer.active && clamp01(pointer.fade ?? 0) > 0;
}

export function getRevealMaskAlpha({
  pointer,
  reveal,
  time,
  x,
  y
}: RevealMaskSample): number {
  if (!reveal) {
    return 0;
  }

  const config = resolveRevealConfig(reveal);
  const radius = Math.max(0, config.radius);

  if (radius === 0) {
    return 0;
  }

  const pixelSize = getRevealPixelSize(config.pixelSize);
  const sampleX = getPixelatedSampleCoordinate(x, pixelSize);
  const sampleY = getPixelatedSampleCoordinate(y, pixelSize);
  const distance = Math.hypot(sampleX - pointer.x, sampleY - pointer.y);

  const softness = clamp01(config.softness);
  const softStart = radius * (1 - softness);
  const edgeWidth = radius - softStart;
  const edgeNoise = edgeWidth > 0 ? clamp01(config.edgeNoise) : 0;
  const outerRadius =
    edgeNoise > 0 && distance > softStart
      ? radius +
        (getEdgeNoise(sampleX, sampleY, pointer.x, pointer.y, getEdgeNoiseCellSize(pixelSize)) -
          0.5) *
          edgeWidth *
          EDGE_NOISE_MAX_WIDTH_MULTIPLIER *
          edgeNoise
      : radius;

  if (distance >= outerRadius) {
    return 0;
  }

  const radialAlpha =
    distance <= softStart
      ? 1
      : 1 - smoothstep(softStart, outerRadius, distance);

  if (radialAlpha <= 0) {
    return 0;
  }

  const edgeDither = clamp01(config.edgeDither);
  const edgeAmount = 1 - radialAlpha;
  const edgeFlicker = clamp01(config.edgeFlicker);
  const edgeDitherSeed =
    edgeFlicker > 0
      ? getEdgeDitherSeed(pointer, pixelSize, time ?? 0, edgeFlicker)
      : undefined;

  if (
    edgeDither > 0 &&
    edgeAmount > 0 &&
    getDitherThreshold(x, y, pixelSize, edgeDitherSeed) < edgeAmount * edgeDither
  ) {
    return 0;
  }

  return clamp01(radialAlpha * clamp01(config.strength) * clamp01(pointer.fade ?? 1));
}

export function getRevealCompositeMaskAlpha(sample: RevealMaskSample): number {
  const baseAlpha = getRevealMaskAlpha(sample);
  const config = resolveRevealConfig(sample.reveal);
  const trailConfig = resolveRevealTrailConfig(config.trail);

  if (!trailConfig) {
    return baseAlpha;
  }

  let trailAlpha = 0;
  const dustFlicker = clamp01(trailConfig.dustFlicker);
  const dustSeedOffset =
    dustFlicker > 0
      ? Math.floor(Math.max(0, sample.time ?? 0) / DUST_FLICKER_STEP_MS) *
        DUST_FLICKER_SEED_SCALE *
        dustFlicker
      : 0;

  for (const point of sample.pointer.trail ?? []) {
    const fade = clamp01(point.fade);
    const seed = point.x * 0.37 + point.y * 0.21 + dustSeedOffset;
    const dustSize = Math.max(1, trailConfig.dustSize);

    if (fade <= 0 || getDustThreshold(sample.x, sample.y, seed, dustSize) > fade) {
      continue;
    }

    trailAlpha = Math.max(
      trailAlpha,
      getRevealMaskAlpha({
        ...sample,
        pointer: {
          active: false,
          fade: clamp01(trailConfig.strength),
          x: point.x,
          y: point.y
        }
      })
    );
  }

  return Math.max(baseAlpha, trailAlpha);
}

export function getDitherThreshold(
  x: number,
  y: number,
  pixelSize = 1,
  seed?: number
): number {
  const safePixelSize = getRevealPixelSize(pixelSize);

  if (seed !== undefined) {
    return getDustThreshold(x, y, seed, safePixelSize);
  }

  const row = modulo(Math.floor(y / safePixelSize), REVEAL_DITHER_MATRIX.length);
  const column = modulo(Math.floor(x / safePixelSize), REVEAL_DITHER_MATRIX[row].length);

  return (REVEAL_DITHER_MATRIX[row][column] + 0.5) / 16;
}

export function getDustThreshold(x: number, y: number, seed = 0, cellSize = 2): number {
  const safeCellSize = Math.max(1, cellSize);
  const cellX = Math.floor(x / safeCellSize);
  const cellY = Math.floor(y / safeCellSize);
  const value =
    Math.sin(cellX * 12.9898 + cellY * 78.233 + seed * 0.037719) * 43758.5453;

  return value - Math.floor(value);
}

export function getEdgeNoise(
  x: number,
  y: number,
  originX: number,
  originY: number,
  cellSize = EDGE_NOISE_CELL_SIZE
): number {
  const safeCellSize = Math.max(1, cellSize);
  const cellX = Math.floor((x - originX) / safeCellSize);
  const cellY = Math.floor((y - originY) / safeCellSize);
  const value = Math.sin(cellX * 127.1 + cellY * 311.7) * 43758.5453123;

  return value - Math.floor(value);
}

function getRevealPixelSize(pixelSize: number | undefined): number {
  return Math.max(1, Math.round(pixelSize ?? 1));
}

function getPixelatedSampleCoordinate(value: number, pixelSize: number): number {
  if (pixelSize <= 1) {
    return value;
  }

  return Math.floor(value / pixelSize) * pixelSize + pixelSize / 2;
}

function getEdgeNoiseCellSize(pixelSize: number): number {
  return pixelSize > 1 ? pixelSize : EDGE_NOISE_CELL_SIZE;
}

function getEdgeDitherSeed(
  pointer: PointerSnapshot,
  pixelSize: number,
  time: number,
  flicker: number
): number {
  const pointerSeed =
    Math.floor(pointer.x / pixelSize) * 0.73 + Math.floor(pointer.y / pixelSize) * 0.41;
  const timeSeed =
    Math.floor(Math.max(0, time) / EDGE_FLICKER_STEP_MS) * EDGE_FLICKER_SEED_SCALE;

  return (pointerSeed + timeSeed) * flicker;
}

function smoothstep(edge0: number, edge1: number, value: number): number {
  if (edge0 === edge1) {
    return value < edge1 ? 0 : 1;
  }

  const t = clamp01((value - edge0) / (edge1 - edge0));

  return t * t * (3 - 2 * t);
}

function modulo(value: number, size: number): number {
  return ((value % size) + size) % size;
}
